  ('judicial-57f41407-moex-00003', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '在反全球化浪潮中，誕生一股新的全球化勢力「另類全球化」，下列那個新聞報導為另類全球化所關注的議題？', '["美聯社：「棕櫚油種植園女工遭殘酷對待剝削，知名跨國美容品牌或涉其中」", "BBC：「1645天大長征結束，英國脫歐戲碼落幕！英國拿回與失去什麼？」", "CNN報導：「封城前也要來杯珍奶，介紹臺灣國民飲料風行全球歷史」", "Fashion-press：「2021年星巴克夢幻櫻花杯浪漫登場！踏青賞櫻必敗」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00004', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「比例代表制」的運作，通常是由選民投票給政黨，再計算各政黨得票數，依得票比例分配各政黨當選名 額。有關此制度的相關分析，下列何者最適當？', '["相較於單一選區制，較有利於小黨", "立法強制選民必須投出兩票選票，又稱為混合投票制", "各政黨推薦候選人的名單，候選人數均須相同", "此制度缺點是政黨得票率與席次的比例無法一致"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00005', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '有關兩岸關係發展之敘述，下列何者正確？', '["1945年後兩岸「進入」武力衝突時期", "1979年後兩岸「進入」和平對峙時期", "1991年後兩岸「進入」民間交流時期", "2008年後兩岸「進入」政治對話時期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00006', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '有關美國政治制度，下列敘述何者正確？', '["美國總統採用選舉人團之間接選舉制度", "美國總統發表國情咨文後必須立即接受國會議員之質詢", "國務卿認為法案窒礙難行時得行使覆議權", "美國總統認有必要時得行使解散國會權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00007', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', 'A為某護膚品牌的區域經銷商，美體護膚店與A進貨時，A約定美體護膚店只能在自家實體店面銷售該護 膚品牌的產品，而不得於網路上銷售。此一作法，可能違反下列何者的規定？', '["公平交易法", "消費者保護法", "民法中的契約自由原則", "民法中的公序良俗原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00008', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '在經濟學上常會使用「生產可能線」來說明機會成本的概念，下列有關「生產可能曲線」的敘述，何者錯誤？', '["是以生產可能線的斜率來衡量機會成本", "在同一條線上的任何一點均具備生產效率", "生產技術的進步與資源的增加皆可使此線外移", "凸向原點的曲線表示機會成本遞增的情況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00009', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '經濟學者認為經濟發展要素包括許多項目，下列有關各種資本的敘述，何者正確？', '["政府科學園區的規劃是重視自然資本的展現", "食品添加毒澱粉事件有損於社會資本的累積", "能擠進世界大學排行的前百大與政府效能密切相關", "企業與學校之間的產學合作是屬於企業才能的運用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00010', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '假設該國為小國，開放貿易前，某商品國內價格比國際價格低，則該國開放貿易後，對於貿易後的敘述， 下列何者正確？', '["該國將進口該商品，生產者剩餘減少", "該國將出口該商品，生產者剩餘增加", "該國將出口該商品，消費者剩餘增加", "該國將進口該商品，消費者剩餘減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00011', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '世界貿易組織（WTO）在國際間扮演著促進國際貿易發展的角色，為此WTO有5項主要原則；若A國自 甲、乙兩國進口汽車之關稅原本分別為25%、30%，當三國都加入WTO後，A國對甲、乙兩國進口汽車 之關稅應都定為25%；此作法（措施）係依據下列WTO的何種原則？', '["關稅優先原則", "國民原則", "最惠國原則", "普遍化優惠關稅原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00012', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2020年新冠肺炎疫情爆發，各國紛紛管制邊境，國際旅遊人數驟降，若民眾對旅遊的喜好未改變。假定某 國之國內旅遊市場十分仰賴國際觀光旅客，請問該國之國內旅遊的需求可能有何變化？', '["沿原先需求線往左上移動", "沿原先需求線往右下移動", "整條需求線往右上移動", "整條需求線往左下移動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
